export const MOCK_EXAMS = [
  {
    id: 'mock1',
    title: 'Mock Exam 1 — Scenario Fundamentals',
    description: 'Core architecture decisions, floor plan selection, and key concepts tested in scenario format.',
    totalTime: 35,
    passMark: 70,
    questions: [
      { id: 'm1q1', scenario: 'You are designing a Fiori app for HR managers to view a list of all employees across regions, filter by department/location/status, and click into employee profiles to edit contact details.', question: 'Which floor plan combination is most appropriate?', choices: ['Worklist + Fact Sheet', 'List Report Page + Object Page', 'Overview Page + Object Page', 'Analytical List Page + Worklist'], correct: 1, explanation: 'List Report Page for filtering 2000+ employees + Object Page for editing individual employee details. Classic LR+OP transactional pattern.' },
      { id: 'm1q2', scenario: 'The "Amount" column in your Fiori elements app shows raw numbers without currency formatting. The CDS view has both "Amount" and "Currency" fields.', question: 'Which annotation links Amount to Currency for proper formatting?', choices: ['@UI.dataPoint: { currency: Currency }', '@Semantics.amount.currencyCode: \'Currency\'', '@UI.lineItem: [{ currency: Currency }]', '@ObjectModel.currency: Currency'], correct: 1, explanation: '@Semantics.amount.currencyCode: \'Currency\' links the amount to its currency field. Fiori elements auto-formats with locale-appropriate currency display.' },
      { id: 'm1q3', scenario: 'A developer has added @UI.chart, @UI.lineItem, and @UI.selectionField to a CDS view but the Analytical List Page chart still doesn\'t display data.', question: 'What is the missing annotation?', choices: ['@UI.presentationVariant linking chart and table', '@Analytics.query: true on the CDS view', '@OData.publish: true to expose the service', '@UI.selectionPresentationVariant on the facet'], correct: 1, explanation: '@Analytics.query: true is mandatory on the CDS view to enable aggregation for the ALP chart. Without it, the backend cannot compute the analytical groupings.' },
      { id: 'm1q4', scenario: 'Your Fiori app on BTP calls an on-premise S/4HANA OData service. After a company firewall rule change that blocks all outbound connections from the on-premise server, the app stops working.', question: 'Why does the firewall change break BTP connectivity?', choices: ['BTP requires inbound connections to on-premise — firewall blocked them', 'Cloud Connector uses outbound connections from on-premise to BTP — blocking outbound breaks the tunnel', 'The Destination Service uses inbound connections that were blocked', 'XSUAA needs outbound access for token validation'], correct: 1, explanation: 'Cloud Connector creates an outbound HTTPS tunnel from on-premise to BTP. No inbound connections are needed. Blocking outbound from the on-premise server kills the Cloud Connector tunnel, breaking all connectivity.' },
      { id: 'm1q5', scenario: 'A user reports that after approving a purchase order in the Fiori app, the list still shows the order as "Pending". The developer checks the code and sees no explicit refresh call.', question: 'What is the SAP OData V4 mechanism for refreshing related entities after an action?', choices: ['Call model.refresh() manually in the action success handler', 'Use Side Effects — annotate the action with @Common.SideEffects to specify which entities to refresh', 'Reload the entire page using window.location.reload()', 'Increase the OData model cache timeout'], correct: 1, explanation: 'SAP OData V4 RAP Side Effects (@Core.OperationAvailable or $Annotations with sideEffects) tell the framework which bindings to refresh after an action executes. The framework automatically re-fetches the affected entities without a full page reload.' },
      { id: 'm1q6', scenario: 'A Fiori elements Object Page has a "Submit" action. After clicking Submit, a confirmation dialog should appear asking "Are you sure you want to submit?"', question: 'How is a confirmation dialog added to a Fiori elements action without custom code?', choices: ['Add a custom dialog fragment in the controller extension', 'Set requiresContext: true and confirmation: {} on the action in the manifest.json action configuration', 'Use sap.m.MessageBox in the OData success handler', 'Configure the dialog in the CDS annotation @UI.lineItem action'], correct: 1, explanation: 'Fiori elements manifest.json action configuration supports built-in confirmation dialogs via the "confirmation" property. Setting enableAutoInvert and confirmation: { title: \'...\', text: \'...\' } triggers a standard confirmation dialog before executing the action — no custom code needed.' },
      { id: 'm1q7', scenario: 'A developer uses sap.ui.require([\'sap/m/MessageBox\'], function(MessageBox) { MessageBox.show(\'Hello\'); }); in a controller.', question: 'What is the purpose of using sap.ui.require() instead of declaring MessageBox in sap.ui.define()?', choices: ['sap.ui.require() is faster than sap.ui.define() for loading modules', 'sap.ui.require() enables lazy loading — the MessageBox module is loaded only when needed, not at app startup', 'sap.ui.define() cannot load sap.m controls — sap.ui.require() must be used', 'They are identical — sap.ui.require() is just the newer API'], correct: 1, explanation: 'sap.ui.require() is for lazy/on-demand loading at the point of use. Modules in sap.ui.define()\'s dependency array are loaded eagerly at startup. Using sap.ui.require() for MessageBox means the module loads only the first time a dialog is shown, improving startup performance.' },
      { id: 'm1q8', scenario: 'A QUnit test is running the controller\'s onApprovePress() function. The function calls this.getView().getModel(\'oData\').callFunction(). The test fails with "getModel is not a function".', question: 'How should this dependency be handled in the unit test?', choices: ['Replace the real OData call with a JSONModel for testing', 'Use sinon.stub(this.oController.getView(), \'getModel\').returns(oFakeModel) in beforeEach to provide a controlled model', 'Skip testing functions that use OData models', 'Run the test against the real OData backend in test mode'], correct: 1, explanation: 'Stub getView().getModel() with sinon to return a fake model object. This isolates the controller logic from the real OData model. The stub can be configured to simulate success or error responses, enabling thorough testing of all code paths without a backend.' },
      { id: 'm1q9', scenario: 'A company migrates 10 Fiori apps from NetWeaver BSP to BTP Cloud Foundry. They ask whether they need to rewrite all the apps or if the existing SAPUI5 code can be reused.', question: 'What is the correct answer regarding SAPUI5 app portability between BSP and BTP CF?', choices: ['All apps must be completely rewritten for BTP Cloud Foundry', 'The SAPUI5 application code (HTML, JS, XML views) is portable — only deployment configuration (MTA, xs-app.json) needs to be added', 'Only apps using OData V4 can be migrated; V2 apps must stay on NetWeaver', 'BTP Cloud Foundry uses different SAPUI5 APIs than NetWeaver'], correct: 1, explanation: 'SAPUI5 application code is completely portable between BSP and BTP CF — the same HTML, JavaScript, XML views, and manifest.json work on both platforms. Migration requires adding: mta.yaml (MTA deployment descriptor), xs-app.json (app router configuration), XSUAA service binding, and Destination configuration.' },
      { id: 'm1q10', scenario: 'A developer adds @UI.selectionField: [{ position: 10 }] to the "Status" field but it appears in the wrong position in the filter bar, after fields positioned at 20 and 30.', question: 'What determines filter bar field order in Fiori elements?', choices: ['Alphabetical order of field names', 'The position value in @UI.selectionField — lower numbers appear first (left side)', 'The order fields appear in the CDS SELECT clause', 'The order @UI.selectionField annotations appear in the source code'], correct: 1, explanation: 'The position number in @UI.selectionField: [{ position: 10 }] directly controls left-to-right order in the Smart Filter Bar. Position 10 appears before position 20, which appears before 30. If Status at position 10 appears after 20/30, check whether those other fields might also have position 10 (causing undefined order) or whether a UI adaptation has changed the layout.' },
      { id: 'm1q11', scenario: 'A developer reviews SAPUI5 documentation and finds that the sap.ui.commons library is marked as "Deprecated". The app still uses controls from this library.', question: 'What does deprecated mean and what action should be taken?', choices: ['Deprecated means the library will be removed immediately — the app is broken', 'Deprecated means the library is stable but scheduled for future removal — migrate to sap.m equivalents in the next major update', 'Deprecated means the library needs a license upgrade to continue using', 'Deprecated libraries perform better — no action needed'], correct: 1, explanation: 'Deprecated in SAPUI5 means: currently still works but will be removed in a future major version. No immediate breaking change, but the team should plan migration to the recommended alternatives (sap.m controls). SAP provides migration guides. Continuing to use deprecated APIs creates future upgrade risk.' },
      { id: 'm1q12', scenario: 'After deploying a Fiori app to BTP, the application loads but the OData data is not showing. Chrome DevTools Network shows the OData requests returning HTTP 200 with an empty data array.', question: 'What is the most likely cause of empty data in OData V4 responses?', choices: ['The Destination Service is not configured correctly', 'The CDS view WHERE clause or ABAP authorization check is filtering out all records for this user', 'The SAPUI5 model is caching old empty data', 'The xs-app.json route is missing the $expand parameter'], correct: 1, explanation: 'HTTP 200 with empty array means the OData service reached the backend and executed successfully, but returned no data. Most common causes: (1) CDS view DCLS (data control) blocking all records for this user, (2) Missing @AbapCatalog.sqlViewName or unmapped fields, (3) ABAP authority checks returning no authorized records. Check CDS view DCLS and backend authorization objects.' },
      { id: 'm1q13', scenario: 'A Fiori elements app was built on SAP S/4HANA 2021. The company upgrades to S/4HANA 2023. After the upgrade, some CDS annotations on custom extensions stop working.', question: 'What is the most likely cause and recommended fix?', choices: ['Custom CDS annotations always break on S/4HANA upgrades — a full redesign is needed', 'Upgrade changed annotation APIs or moved standard CDS views — review SAP release notes and update custom annotations to the new paths', 'The BTP deployment must be rebuilt to match the S/4HANA version', 'Custom annotations are not supported across S/4HANA versions'], correct: 1, explanation: 'S/4HANA upgrades can change standard CDS view names, rename annotation namespaces, or deprecate specific annotation formats. Check the S/4HANA 2023 release notes and What\'s New Viewer for annotation API changes. Update custom extensions to use the new annotation paths. This is why using SAP\'s documented, stable extension points is crucial — undocumented extensions break more often.' },
      { id: 'm1q14', scenario: 'A Fiori developer is asked to implement Draft functionality for a purchase order creation app, allowing users to save incomplete orders and resume later.', question: 'Which SAP technology provides built-in Draft Handling for Fiori elements apps?', choices: ['OData V2 function imports for save-as-draft', 'ABAP RAP (RESTful Application Programming Model) with OData V4 — has native Draft Handling', 'Custom ABAP function module storing draft data in a Z-table', 'Fiori elements V2 with manual draft management in controller'], correct: 1, explanation: 'ABAP RAP with OData V4 has built-in Draft Handling as a first-class feature. Draft entities get their own set of operations (draftPrepare, draftActivate), Fiori elements automatically renders draft indicators and resume flows. The RAP behaviour definition includes draft: managed; specifying which entity supports drafts. No custom code needed for the draft lifecycle.' },
      { id: 'm1q15', scenario: 'A company wants to deploy their Fiori apps once and have them work for all regional offices (USA, Germany, Japan) with proper date formats, currency displays, and translated labels.', question: 'Which SAPUI5 feature handles all three localisation requirements automatically?', choices: ['Custom formatters for each region written in JavaScript', 'SAPUI5\'s built-in formatting based on browser locale + ResourceModel for i18n text + OData annotations for semantic types', 'Separate app deployments per region with hardcoded locale settings', 'Manual locale detection in onInit() and conditional formatting'], correct: 1, explanation: 'SAPUI5 handles localisation via multiple mechanisms: ResourceModel automatically loads locale-specific .properties files (i18n_de.properties for German). sap.ui.core.format.DateFormat and NumberFormat use browser locale automatically. @Semantics.amount.currencyCode annotations enable auto currency formatting. Together these handle dates, numbers, and text translations without separate regional deployments.' },
    ],
  },

  {
    id: 'mock2',
    title: 'Mock Exam 2 — Advanced Scenarios',
    description: 'Complex real-world scenarios spanning FPM, security, performance, and deployment.',
    totalTime: 40,
    passMark: 70,
    questions: [
      { id: 'm2q1', scenario: 'A developer creates a Fiori elements app using OData V4. Users report that after editing a field in a form, related calculated fields (like Total = Qty × Price) don\'t update until the page is refreshed.', question: 'Which OData V4 mechanism handles automatic UI refresh of related fields after edits?', choices: ['Add requestRefresh() calls after every field change event', 'Configure Side Effects on the property — @Core.OperationAvailable and side effects annotations trigger targeted re-reads', 'Enable auto-refresh in the OData model constructor', 'Use a value change event in the controller extension to manually recalculate'], correct: 1, explanation: 'OData V4 Side Effects enable the framework to automatically re-read specific properties when related fields change. In RAP, annotate the property with SideEffects targeting TargetProperties: [\'TotalAmount\'] when Quantity changes. Fiori elements reads these annotations and triggers targeted GET requests, refreshing only the affected fields without a full page reload.' },
      { id: 'm2q2', scenario: 'A company has 1000 users accessing a Fiori app. A load test shows the BTP app router instance running at 95% CPU when all users are active simultaneously.', question: 'What is the recommended BTP scaling approach for this bottleneck?', choices: ['Increase the app router memory allocation', 'Scale horizontally — add more app router instances via Cloud Foundry cf scale command or auto-scaling policies', 'Optimize the SAPUI5 code to reduce app router CPU load', 'Move the app router to a larger BTP service plan'], correct: 1, explanation: 'Cloud Foundry supports horizontal scaling: cf scale app-router -i 3 adds 3 instances with load balancing. BTP Application Router also supports auto-scaling policies that add instances based on CPU/memory thresholds. Horizontal scaling is preferred over vertical (larger instances) as it provides better resilience and cost efficiency.' },
      { id: 'm2q3', scenario: 'A Fiori developer notices that the List Report table columns are all showing correctly but filters are not persisting between navigation — every time the user returns to the List Report, all filters are reset.', question: 'Which Fiori elements feature preserves filter and sort settings between navigation?', choices: ['Browser sessionStorage automatically saves filter state', 'Fiori elements\' built-in Variant Management — users can save and restore filter sets as named variants', 'The onBeforeRendering hook saves filter state to JSONModel', 'OData $select parameters remember previous filter state'], correct: 1, explanation: 'Fiori elements includes Variant Management (SmartVariantManagement) built into the List Report filter bar. Users can save current filter/sort/column settings as named variants (personal or shared). The selected variant is restored automatically on next navigation. This feature requires SAPUI5 persistence (stored via sap.ui.core.Lib.load or backend persistence).' },
      { id: 'm2q4', scenario: 'A developer is writing a controller extension for a Fiori elements Object Page. They need to call this.base.getModel(\'oData\') but get "TypeError: this.base is undefined".', question: 'What does this.base refer to in a Fiori elements controller extension?', choices: ['The standard Fiori elements base controller class methods', 'The extension\'s parent class in the JavaScript prototype chain', 'this.base is not a valid API — use this._oPageController instead', 'The manifest.json base configuration object'], correct: 0, explanation: 'In Fiori elements controller extensions, this.base provides access to the standard Fiori elements page controller\'s API — methods like this.base.getModel(), this.base.getView(), this.base.getExtensionAPI(). If this.base is undefined, the extension is not properly inheriting from the Fiori elements extension point — check the extension registration in manifest.json.' },
      { id: 'm2q5', scenario: 'A Fiori app uses $batch for OData V2 requests. The developer notices some batch calls fail silently — the batch HTTP response is 200 but individual operations inside returned 500 errors.', question: 'How should OData $batch error responses be handled in SAPUI5?', choices: ['OData $batch always returns 200 — no error handling needed inside batch responses', 'Listen to the ODataModel batchRequestFailed event and inspect individual changeSet errors in the error callback', 'Use try/catch around the batch call — exceptions are thrown for any batch error', 'Check the HTTP status of the $batch response and handle 200 as success, 500 as error'], correct: 1, explanation: 'OData $batch always returns HTTP 200 (the outer envelope succeeded). Individual operations within the batch can fail. In SAPUI5 V2 ODataModel, the error handler of submitBatch() or individual operation callbacks receive the changeSet failure details. Always handle both the batch-level success callback AND individual operation error callbacks.' },
      { id: 'm2q6', scenario: 'A Fiori elements List Report shows 10 columns. Business users complain that the most important column (\'Priority\') is hidden off-screen to the right. They want it as the second column, but the developer is on vacation.', question: 'How can a business key user move the Priority column without developer involvement?', choices: ['Submit a ServiceNow ticket for the developer to update @UI.lineItem position', 'Use SAP UI5 Flexibility Key User Adaptation (Adapt UI) to reorder columns at runtime', 'Export the table to Excel and reorder the columns there', 'Configure column order via PFCG role settings'], correct: 1, explanation: 'Key User Adaptation (enabled via the F4 Adapt UI button or BTP Launchpad customisation) allows designated business users to rearrange columns, add/hide columns, rename headers, and save these as app-level defaults. Changes are stored as SAPUI5 Flexibility change files in BTP. No developer or redeployment needed.' },
      { id: 'm2q7', scenario: 'A developer implements an OData V4 unbound action called "SendApprovalEmail". After calling the action, the List Report data should refresh automatically.', question: 'How does the Fiori elements framework know to refresh the List Report after this action?', choices: ['All actions automatically refresh the full page', 'Configure sideEffects on the action in the CDS annotation or manifest.json to specify which EntitySet to refresh', 'Call this.getView().getModel().refresh() in the action\'s success handler', 'The action must be defined as a bound action to trigger refresh'], correct: 1, explanation: 'Side Effects configuration tells Fiori elements what to refresh after an action. In manifest.json action configuration: sideEffects: { targetEntities: [{ $NavigationPropertyPath: \'\' }] } refreshes the current entity. For a List Report refresh, target the EntitySet. In CDS, @Core.OperationAvailable and @Capabilities.SupportedFormats with side effects achieve the same.' },
      { id: 'm2q8', scenario: 'A company\'s Fiori app has a memory leak — the browser\'s memory usage grows continuously as users navigate between List Report and Object Page. After an hour, the app crashes.', question: 'What is the most common cause of SAPUI5 memory leaks?', choices: ['Too many @UI.lineItem annotations creating excessive DOM elements', 'Event listeners or model subscriptions attached in controller lifecycle methods but never detached in onExit()', 'OData V4 caching storing too many entities in memory', 'JavaScript closure captures preventing garbage collection of controller variables'], correct: 1, explanation: 'The most common SAPUI5 memory leak: attaching event listeners (EventBus subscriptions, OData model event listeners, external event listeners) in onInit() or onBeforeRendering() without detaching them in onExit(). Each time the view is created and destroyed, another listener accumulates. Fix: always detach in onExit(): this.getOwnerComponent().getEventBus().unsubscribe(...).' },
      { id: 'm2q9', scenario: 'A project team is debating whether to use SAP Build Work Zone or the native BTP Fiori Launchpad Service for their centralised Fiori portal serving 5000 users.', question: 'What is the key advantage of SAP Build Work Zone over native Launchpad Service?', choices: ['Build Work Zone has lower cost per user than Launchpad Service', 'Build Work Zone adds workspace collaboration, integration of non-SAP apps, cards/widgets, and a content federation hub for complex enterprise portals', 'Build Work Zone has better performance for large user counts', 'Build Work Zone supports PFCG roles while Launchpad Service requires XSUAA only'], correct: 1, explanation: 'SAP Build Work Zone (formerly SAP Launchpad Service + Work Zone) adds: workspace collaboration (like SharePoint/Teams integration), UI Integration Cards, ability to integrate non-SAP third-party apps, and a content federation model that aggregates content from multiple SAP and non-SAP systems. For a simple Fiori portal, native Launchpad Service is sufficient; for complex enterprise portals with collaboration, Work Zone is recommended.' },
      { id: 'm2q10', scenario: 'A developer reads in the SAPUI5 changelog that sap.ui.table.Table\'s rowCount property is deprecated in favour of visibleRowCount. The current app uses rowCount.', question: 'What is the recommended approach when SAPUI5 deprecates an API the app uses?', choices: ['Continue using the deprecated API — it will never be actually removed', 'Immediately refactor to the new API in a hotfix to avoid production issues', 'Plan migration to visibleRowCount in the next sprint cycle — deprecated APIs are supported for several major versions before removal', 'Contact SAP Support to undo the deprecation for backward compatibility'], correct: 2, explanation: 'SAP\'s deprecation policy maintains deprecated APIs for at minimum 1-2 major SAPUI5 versions before removal. "Deprecated" means: use the new API for new code, and plan migration (not emergency hotfix) for existing code. SAP provides migration guides and the API reference marks the migration target. The team should address it in the normal sprint cycle.' },
      { id: 'm2q11', scenario: 'A Fiori app shows "Error: Metadata unavailable" on startup. The OData service metadata URL returns HTTP 404.', question: 'What are the two most likely causes of a metadata 404 error?', choices: ['The OData model configuration and $batch are incompatible', 'Wrong OData service path in manifest.json dataSources uri, or the OData service is not activated/deployed on the backend', 'The SAPUI5 version is incompatible with the OData version', 'The Destination Service has expired and needs renewal'], correct: 1, explanation: 'HTTP 404 for metadata usually means: (1) Wrong service path in manifest.json dataSources — the uri points to a non-existent service. (2) The OData service exists in code but hasn\'t been activated in SAP Gateway (transaction /IWFND/MAINT_SERVICE) or the backend. Check the uri value and verify the service is active and returns metadata when called directly.' },
      { id: 'm2q12', scenario: 'A performance analysis shows that a Fiori List Report page renders 5,000 table rows at once, causing DOM bloat and scroll lag on mobile devices.', question: 'Which SAPUI5 feature efficiently handles large datasets in tables without loading all rows into the DOM?', choices: ['sap.m.List with growingThreshold property limiting DOM items + server-side $skip/$top', 'sap.ui.table.Table with row virtualisation — only renders visible rows + page buffer in the DOM', 'sap.m.Table with fixedLayout: true for better rendering performance', 'Increase the browser tab memory allocation for better performance'], correct: 1, explanation: 'sap.ui.table.Table (Grid Table) uses row virtualisation — it only renders the currently visible rows plus a small buffer in the DOM, regardless of how many rows are in the dataset. As users scroll, it reuses DOM nodes with new data. This makes 10,000 rows perform identically to 50 rows from a rendering perspective. sap.m.Table renders all items in the DOM.' },
      { id: 'm2q13', scenario: 'A company wants to implement a "Zero Downtime" deployment for their Fiori app on BTP — new version goes live while old version continues serving users until all sessions complete.', question: 'Which BTP Cloud Foundry deployment strategy achieves zero downtime?', choices: ['Deploy with cf push overwriting the existing app', 'Blue-Green deployment — deploy new version as separate app, then switch routing, keep old app running until sessions drain', 'Use SAP BTP\'s rolling deployment feature in the manifest.yml', 'Deploy to test, then manually copy files to production'], correct: 1, explanation: 'Blue-Green deployment: (1) Deploy new "green" app alongside existing "blue" app. (2) Test green thoroughly. (3) Switch Cloud Foundry routing from blue to green (cf map-route / cf unmap-route). (4) Old blue app keeps running until existing sessions complete, then unmap blue route. SAP CI/CD Service and MTA deployment support blue-green natively.' },
      { id: 'm2q14', scenario: 'A Fiori app developer is asked to implement "pessimistic locking" for purchase order editing — only one user should be able to edit a PO at a time.', question: 'Which SAP OData V4 mechanism implements business object locking?', choices: ['JavaScript session storage tracks which user has the object open', 'ABAP RAP with OData V4 draft handling implements optimistic locking — last writer wins', 'ABAP lock objects (ENQUEUE) with OData V4 — lock on edit, release on save/cancel', 'The ETags mechanism in OData V4 headers prevents concurrent updates'], correct: 2, explanation: 'ABAP lock objects (transaction SE11, object type LOCK) with ENQUEUE/DEQUEUE function modules provide pessimistic locking. When a user starts editing, ENQUEUE reserves the lock; saving or cancelling calls DEQUEUE. This prevents simultaneous editing. In OData V4 RAP, lock handling can be integrated into the RAP behaviour definition. ETags are optimistic (concurrent edits allowed until save-time conflict).' },
      { id: 'm2q15', scenario: 'A Fiori app was extended by copying the standard app 18 months ago. The copied app now has 30+ modifications. The team is asked to adopt the standard extensibility approach going forward.', question: 'What is the recommended migration strategy from a copy-based to extension-based approach?', choices: ['Immediately delete the copy and start over with a fresh extension-only approach', 'Analyse each of the 30+ modifications — categorise as controller extension, custom fragment, or annotation — then re-implement in the extension framework progressively across sprints', 'Keep the copy permanently — migration is too risky at this point', 'Use an automated SAP tool that converts copy-based apps to extension apps'], correct: 1, explanation: 'Migration strategy: (1) Inventory all 30+ modifications. (2) Categorise: UI changes → custom fragments; logic changes → controller extensions; data filtering → CDS annotations. (3) Re-implement in priority order across sprints, testing each extension before removing the corresponding copy modification. (4) Once all modifications are re-implemented as extensions, switch back to the standard app base. Progressive, low-risk migration.' },
    ],
  },

  {
    id: 'mock3',
    title: 'Mock Exam 3 — Full Scenario Simulation',
    description: 'Complete end-to-end scenarios simulating the actual C_FIORD_2601 assessment format.',
    totalTime: 45,
    passMark: 70,
    questions: [
      { id: 'm3q1', scenario: 'A retail company needs a Fiori app where store managers can see daily sales KPIs (revenue, transactions, avg basket), drill into product category performance charts, and filter by region and date. This is purely analytical — no editing.', question: 'What is the complete recommended solution stack?', choices: ['Worklist + JSONModel + custom charts', 'Analytical List Page + OData V4 analytical query + @Analytics.query: true + @UI.chart annotations + CDS with measure aggregations', 'Overview Page + multiple chart cards + separate OData services', 'List Report Page with embedded SmartChart + @UI.lineItem'], correct: 1, explanation: 'The ALP is designed for analytical + operational combined use. Required stack: OData V4 analytical service (RAP or traditional analytical query) + @Analytics.query: true on CDS + @UI.chart defining chart type/dimensions/measures + @UI.selectionField for filters. ALP automatically generates visual filters, chart, and table from these annotations.' },
      { id: 'm3q2', scenario: 'A developer looks at this code in a controller extension:\nthis.byId(\'approveBtn\').setVisible(false);\nAnd this OData action:\nthis.getView().getModel().callFunction(\'/ApproveOrder\', {\n  method: \'POST\'\n});', question: 'Which of these two code snippets is a security concern and why?', choices: ['The OData call is a security risk — POST calls are vulnerable to CSRF attacks', 'Setting setVisible(false) is a security risk — UI hiding is not real security; authorization must be enforced in the backend OData service', 'Both are security risks — never use controller extensions for auth', 'Neither — both are standard secure patterns'], correct: 1, explanation: 'setVisible(false) is UX-only — any user can call the OData ApproveOrder function directly via browser console bypassing the UI entirely. Security MUST be enforced in the backend: the OData service\'s /ApproveOrder function must check ABAP authorization objects (authority-check) before executing. Never rely on UI hiding as a security control.' },
      { id: 'm3q3', scenario: 'Building a greenfield project: 25 Fiori apps for SAP S/4HANA 2023 Cloud. The architecture team asks: "Should we use OData V2 or V4 for new development?"', question: 'What is SAP\'s official recommendation for new Fiori development on S/4HANA 2023+?', choices: ['OData V2 — it is more mature and has more documentation', 'OData V4 with ABAP RAP — SAP\'s strategic direction; required for FPM, draft handling, and side effects', 'Either — choose based on team preference', 'OData V3 — SAP\'s intermediate recommended version'], correct: 1, explanation: 'SAP officially recommends OData V4 with ABAP RAP for all new development on S/4HANA 2022+. OData V4 is required for: FPM building blocks, draft handling, side effects, advanced filtering, and aligns with SAP\'s BTP and cloud strategy. OData V2 remains supported for existing services but should not be chosen for new development.' },
      { id: 'm3q4', scenario: 'A developer adds a custom XML view with a Fiori elements Table building block:\n<macros:Table id="OrdersTable" metaPath="@UI.LineItem" />\nThe table does not render — the developer sees only an empty area.', question: 'What is wrong with the metaPath value in this building block?', choices: ['The id attribute format is incorrect', 'metaPath should use the full annotation vocabulary URI: "@com.sap.vocabularies.UI.v1.LineItem" not the shorthand "@UI.LineItem"', 'macros:Table requires an entitySet attribute instead of metaPath', 'The XML namespace declaration for macros is missing'], correct: 1, explanation: 'FPM building block metaPath must use the full OData annotation vocabulary namespace: @com.sap.vocabularies.UI.v1.LineItem (not shorthand @UI.LineItem which is valid in CDS but not in XML view metaPath). Also note @UI.LineItem vs @UI.lineItem — the annotation uses camelCase "lineItem" in CDS, but the vocabulary vocabulary path uses "LineItem". Always use the full qualified name in metaPath.' },
      { id: 'm3q5', scenario: 'A company\'s Fiori Launchpad shows Role-based access. A user who should only have "View" access to purchase orders finds they can also "Create" and "Delete" via the Launchpad and OData service.', question: 'In which order should the security layers be fixed?', choices: ['Fix UI first (hide Create/Delete buttons), then fix OData later when convenient', 'Fix both simultaneously — backend OData authorization is critical and cannot be left unsecured', 'Fix PFCG roles first, then evaluate if UI changes are needed', 'Only fix the Launchpad tile target mapping — that controls all access'], correct: 1, explanation: 'Both must be fixed immediately and simultaneously: (1) PFCG authorization objects (e.g., restricting M_EINKBELEG BSART to view-only activities) prevents the OData service from executing unauthorized operations. (2) UI changes (hiding buttons) improve UX so users don\'t see unavailable actions. Security fix = backend first, but both should be done together — never defer backend authorization fixes.' },
      { id: 'm3q6', scenario: 'A CI/CD pipeline for a Fiori app on BTP must build and deploy automatically on every merge to the main branch. The app is packaged as an MTA.', question: 'What does the MTA build process (mbt build) produce?', choices: ['A compiled JavaScript bundle ready to serve from any web server', 'An MTAR (Multi-Target Application Archive) — a single deployable package containing the UI app, app router, and service bindings', 'A Docker container with the full BTP runtime', 'A zip file of the SAPUI5 source files for manual upload to BTP'], correct: 1, explanation: 'mbt build (MTA Build Tool) compiles the mta.yaml descriptor and all included modules (HTML5 app, app router, XSUAA config, etc.) into an MTAR (*.mtar) archive file. This MTAR is then deployed to Cloud Foundry with cf deploy *.mtar (or via SAP CI/CD Service). The MTAR is the standard deployable artifact for BTP Cloud Foundry multi-module applications.' },
      { id: 'm3q7', scenario: 'A Fiori app developer is asked to implement "Save as Draft" functionality allowing users to start a complex purchase order and save intermediate state without committing to the backend.', question: 'Which technology combination provides native draft handling in SAP Fiori?', choices: ['Custom JSONModel storage + OData POST on final submit', 'ABAP RAP with draft: managed + Fiori elements OData V4 — built-in draft lifecycle management', 'Browser IndexedDB for local draft storage + sync on submit', 'SAP Build Apps low-code draft management components'], correct: 1, explanation: 'ABAP RAP with draft: managed in the behaviour definition provides native draft handling. Fiori elements automatically recognises draft-enabled entities and renders: draft indicator badges, "Resume editing" prompts, draft discard functionality. The full draft lifecycle (draftPrepare, draftActivate, discard) is managed by the framework — zero custom code required.' },
      { id: 'm3q8', scenario: 'After a SAPUI5 version upgrade from 1.108 to 1.120, a custom control that extended sap.m.Input stopped working with "TypeError: oInput._getPopupAnchorDomRef is not a function".', question: 'What caused this break and what is the lesson?', choices: ['The SAPUI5 version upgrade contained a bug — raise an OSS ticket', 'The custom control used a private API (_getPopupAnchorDomRef starting with underscore) that was removed in 1.120 — use only public documented APIs', 'sap.m.Input is deprecated in 1.120 — migrate to sap.m.SmartField', 'Custom controls must be re-registered after SAPUI5 version changes'], correct: 1, explanation: 'SAP prefix convention: _ prefix = private API, no stability guarantee. Public APIs (no underscore) are stable across versions. SAP removed _getPopupAnchorDomRef in 1.120 as an internal implementation detail. Using private APIs is a critical anti-pattern: they can change or disappear in any SAPUI5 release. Always use only the documented public API surface.' },
      { id: 'm3q9', scenario: 'A team is building 20 Fiori apps in parallel across 5 developers. They use Git in SAP BAS. Developer A works on feature/approval-flow and Developer B works on feature/filter-improvements. Both edit manifest.json.', question: 'What is the correct Git workflow to handle this parallel development safely?', choices: ['Both developers push directly to main — last push wins', 'Use feature branches; merge to develop via Pull Request with code review; merge develop to main only after testing; resolve manifest.json conflicts using BAS merge editor', 'Use a single developer as "manifest.json owner" — all changes go through them', 'Separate the manifest.json into multiple files (not possible in SAPUI5 — avoid the conflict']  , correct: 1, explanation: 'Standard Git feature branch workflow: each developer works on a named feature branch. Pull Requests (PRs) enforce code review before merging to develop. Manifest.json conflicts (common since everyone edits it) are resolved in the BAS/VS Code 3-way merge editor, which shows current, incoming, and base versions side by side. This is the industry-standard approach for team-based Fiori development.' },
      { id: 'm3q10', scenario: 'A Fiori app shows translation key strings (e.g., "APPROVE_BUTTON_LABEL") instead of actual translated text in the UI. The i18n model is registered in manifest.json.', question: 'What are the two most common causes of i18n keys displaying as raw text?', choices: ['The ResourceModel is loading asynchronously and hasn\'t resolved yet', 'Either the i18n model name in manifest.json doesn\'t match the binding prefix in XML views ({i18n>key}), or the i18n.properties file path in manifest.json is wrong and the file isn\'t found', 'The i18n.properties file uses UTF-8 encoding but SAPUI5 requires ISO-8859-1', 'The binding uses double curly braces instead of single: {{i18n>key}}'], correct: 1, explanation: 'Two most common causes: (1) Model name mismatch — manifest.json registers it as "i18n" but XML view uses {myI18n>key} — they must match exactly. (2) Wrong file path — uri: "i18n/i18n.properties" in manifest.json doesn\'t find the file because it\'s actually at "webapp/i18n/i18n.properties" — the uri is relative to the webapp folder root.' },
      { id: 'm3q11', scenario: 'A company deploys a Fiori app and wants to track how many users open specific apps, which features are used most, and where users drop off (never complete a task).', question: 'Which SAP tool provides Fiori app usage analytics?', choices: ['SAP Cloud ALM — monitors technical performance metrics', 'SAP Analytics Cloud — real-time BI dashboard of user behavior', 'SAP Fiori Cloud Launchpad analytics + SAP User Activity Reporting (user/session tracking) + custom SAP BTP Application Logging', 'SAPUI5 DevTools — Chrome extension for development analytics'], correct: 2, explanation: 'For Fiori usage analytics: SAP Launchpad Service provides basic tile-click and app-launch statistics. For detailed user journey analytics, SAP recommends integrating with SAP Adoption Reporting or custom logging via SAP BTP Application Logging Service (Elasticsearch-based). Third-party analytics (Matomo, custom event tracking) can be integrated via SAPUI5\'s FioriElementsAnalytics API.' },
      { id: 'm3q12', scenario: 'A developer uses @UI.facets to create three tabs on an Object Page: General, Items, and Documents. The "Items" tab contains a table of line items from a navigation association.', question: 'Which annotation structure correctly creates a table section from a navigation association?', choices: ['@UI.lineItem on the association target entity — no facet needed for associated tables', '@UI.facets: [{ $Type: \'UI.ReferenceFacet\', Target: \'_Items/@UI.LineItem\', Label: \'Items\' }] — navigation path prefix + annotation on associated entity', '@UI.facets: [{ $Type: \'UI.CollectionFacet\', Facets: [{ Target: \'Items/@UI.lineItem\' }] }]', '@UI.table: [{ association: \'_Items\', annotation: \'@UI.lineItem\' }]'], correct: 1, explanation: 'For navigation associations in Object Page facets, use ReferenceFacet with Target pointing to the navigation association path prefix then the annotation: \'_Items/@UI.LineItem\'. The underscore convention \'_Items\' is a CDS association name. This creates a smart table section showing the associated Items entity\'s @UI.LineItem annotations as columns.' },
      { id: 'm3q13', scenario: 'A Fiori app needs to display a custom SVG map widget showing delivery locations on the Object Page alongside standard Fiori elements fields.', question: 'How should this third-party/custom widget be integrated into a Fiori elements Object Page?', choices: ['Embed the SVG directly in the CDS annotation using @UI.identification', 'Create a custom section extension point with a custom XML fragment containing the SVG/map component, declared in manifest.json under the Object Page\'s controlConfiguration', 'Add the SVG in the Object Page\'s headerInfo annotation', 'Create a standalone custom controller that renders the map next to the Object Page'], correct: 1, explanation: 'Custom content in Fiori elements Object Pages uses the custom section extension point. In manifest.json: define a custom section under \'sap.ui.generic.app\' (V2) or in the \'options\' > \'controlConfiguration\' (V4) configuration. The section references a custom XML fragment that can contain any SAPUI5 or HTML5 content including SVG, maps, or third-party widgets.' },
      { id: 'm3q14', scenario: 'A company\'s Fiori app suddenly stops working after 6 months of stable operation. No code was changed. The error message is: "CSRF token validation failed".', question: 'What is the most likely cause of sudden CSRF token failures?', choices: ['The SAPUI5 CSRF protection was recently enabled in a framework update', 'The OData service\'s CSRF token expired or the backend session timed out — the app needs to re-fetch the CSRF token', 'The PFCG role was changed and revoked CSRF token permissions', 'The Cloud Connector certificate expired, causing token validation to fail'], correct: 1, explanation: 'CSRF tokens have a limited validity period tied to the backend session. After long inactivity or session timeout, the stored CSRF token becomes invalid. The SAPUI5 OData model should handle automatic CSRF token re-fetch on 403 CSRF errors (set refreshAfterChange: true in OData model config). If the app doesn\'t handle this, users must refresh. The fix: configure automatic CSRF token refresh or re-fetch token on 403.' },
      { id: 'm3q15', scenario: 'A developer wants to implement infinite scroll on a Fiori elements List Report table (load more rows as user scrolls down) instead of the standard pagination buttons.', question: 'How is progressive loading / growing configured in a Fiori elements List Report?', choices: ['Add growing: true and growingThreshold: 50 as manifest.json settings for the table', 'Configure the table\'s growing property in manifest.json under the List Report\'s tableSettings: { type: \'ResponsiveTable\', growing: \'Scroll\' }', 'Use OData $skiptoken in the controller extension for cursor-based pagination', 'Fiori elements does not support infinite scroll — use pagination only'], correct: 1, explanation: 'In Fiori elements manifest.json, the List Report table settings support growing configuration. For responsive tables: tableSettings: { growing: \'Scroll\' } enables automatic load-more on scroll. For grid tables: growing: \'Page\' adds load-more buttons. The table type must be ResponseTable for scroll growing. The OData service must support $top/$skip (all standard services do) for server-side pagination.' },
    ],
  },
];
